from __future__ import annotations

from dataclasses import asdict, dataclass, field, is_dataclass
import hashlib
import json
from typing import Any, Dict, List, Mapping, Optional


VALID_SIDE_VALUES = {"BUY", "SELL", "LONG", "SHORT"}


class AllocationCandidateError(RuntimeError):
    """Raised when allocation candidate inputs are invalid."""


def _require_non_empty_string(name: str, value: Any) -> str:
    if not isinstance(value, str) or not value.strip():
        raise AllocationCandidateError(f"{name} must be a non-empty string")
    return value.strip()


def _normalize_chain(value: Any) -> str:
    return _require_non_empty_string("chain", value).lower()


def _normalize_strategy_id(value: Any) -> str:
    return _require_non_empty_string("strategy_id", value).lower()


def _normalize_symbol(value: Any) -> str:
    return _require_non_empty_string("symbol", value).upper()


def _normalize_pair(value: Any) -> str:
    return _require_non_empty_string("pair", value).upper()


def _normalize_side(value: Any) -> str:
    normalized = _require_non_empty_string("side", value).upper()
    if normalized not in VALID_SIDE_VALUES:
        raise AllocationCandidateError(
            f"side must be one of {sorted(VALID_SIDE_VALUES)}"
        )
    return normalized


def _normalize_non_negative_int(name: str, value: Any) -> int:
    if isinstance(value, bool) or not isinstance(value, int):
        raise AllocationCandidateError(f"{name} must be a non-negative integer")
    if value < 0:
        raise AllocationCandidateError(f"{name} must be a non-negative integer")
    return value


def _normalize_positive_int(name: str, value: Any) -> int:
    normalized = _normalize_non_negative_int(name, value)
    if normalized <= 0:
        raise AllocationCandidateError(f"{name} must be a positive integer")
    return normalized


def _normalize_non_negative_float(name: str, value: Any) -> float:
    if isinstance(value, bool):
        raise AllocationCandidateError(f"{name} must be a non-negative number")
    if isinstance(value, str):
        try:
            value = float(value.strip())
        except ValueError as exc:
            raise AllocationCandidateError(f"{name} must be a non-negative number") from exc
    if not isinstance(value, (int, float)):
        raise AllocationCandidateError(f"{name} must be a non-negative number")
    normalized = float(value)
    if normalized < 0.0:
        raise AllocationCandidateError(f"{name} must be a non-negative number")
    return normalized


def _normalize_positive_float(name: str, value: Any) -> float:
    normalized = _normalize_non_negative_float(name, value)
    if normalized <= 0.0:
        raise AllocationCandidateError(f"{name} must be a positive number")
    return normalized


def _normalize_metadata(value: Any) -> Dict[str, Any]:
    if value is None:
        return {}
    if not isinstance(value, Mapping):
        raise AllocationCandidateError("metadata must be a mapping when provided")
    return dict(value)


def _normalize_string_list(name: str, value: Any) -> List[str]:
    if value is None:
        return []
    if not isinstance(value, list):
        raise AllocationCandidateError(f"{name} must be a list when provided")
    normalized: List[str] = []
    for item in value:
        normalized.append(_require_non_empty_string(f"{name}[]", item))
    return normalized


def _mapping_from_value(name: str, value: Any) -> Dict[str, Any]:
    if value is None:
        raise AllocationCandidateError(f"{name} is required")

    if isinstance(value, Mapping):
        return dict(value)

    to_dict = getattr(value, "to_dict", None)
    if callable(to_dict):
        payload = to_dict()
        if not isinstance(payload, Mapping):
            raise AllocationCandidateError(f"{name}.to_dict() must return a mapping")
        return dict(payload)

    if is_dataclass(value) and not isinstance(value, type):
        payload = asdict(value)
        if not isinstance(payload, dict):
            raise AllocationCandidateError(f"{name} dataclass did not normalize to a dict")
        return payload

    if hasattr(value, "__dict__"):
        return {key: item for key, item in vars(value).items() if not key.startswith("_")}

    raise AllocationCandidateError(f"{name} must be mapping-like or expose to_dict()")


def _stable_id(prefix: str, payload: Mapping[str, Any]) -> str:
    digest = hashlib.sha256(
        json.dumps(dict(payload), sort_keys=True, default=str).encode("utf-8")
    ).hexdigest()[:16]
    return f"{prefix}_{digest}"


@dataclass(frozen=True)
class AllocationCandidateLineage:
    ranked_opportunity_id: str
    ranking_run_id: str
    scanner_run_id: str
    source_opportunity_id: Optional[str] = None
    strategy_signal_id: Optional[str] = None
    metadata: Dict[str, Any] = field(default_factory=dict)
    allocation_candidate_lineage_id: str = field(init=False)

    def __post_init__(self) -> None:
        ranked_opportunity_id = _require_non_empty_string(
            "ranked_opportunity_id",
            self.ranked_opportunity_id,
        )
        ranking_run_id = _require_non_empty_string("ranking_run_id", self.ranking_run_id)
        scanner_run_id = _require_non_empty_string("scanner_run_id", self.scanner_run_id)
        source_opportunity_id = (
            _require_non_empty_string("source_opportunity_id", self.source_opportunity_id)
            if self.source_opportunity_id is not None
            else None
        )
        strategy_signal_id = (
            _require_non_empty_string("strategy_signal_id", self.strategy_signal_id)
            if self.strategy_signal_id is not None
            else None
        )
        metadata = _normalize_metadata(self.metadata)

        object.__setattr__(self, "ranked_opportunity_id", ranked_opportunity_id)
        object.__setattr__(self, "ranking_run_id", ranking_run_id)
        object.__setattr__(self, "scanner_run_id", scanner_run_id)
        object.__setattr__(self, "source_opportunity_id", source_opportunity_id)
        object.__setattr__(self, "strategy_signal_id", strategy_signal_id)
        object.__setattr__(self, "metadata", metadata)
        object.__setattr__(
            self,
            "allocation_candidate_lineage_id",
            _stable_id(
                "allocation_candidate_lineage",
                {
                    "ranked_opportunity_id": ranked_opportunity_id,
                    "ranking_run_id": ranking_run_id,
                    "scanner_run_id": scanner_run_id,
                    "source_opportunity_id": source_opportunity_id,
                    "strategy_signal_id": strategy_signal_id,
                },
            ),
        )

    def to_dict(self) -> Dict[str, Any]:
        payload = asdict(self)
        payload["metadata"] = dict(self.metadata)
        return payload

    @classmethod
    def from_dict(cls, payload: Mapping[str, Any]) -> "AllocationCandidateLineage":
        if not isinstance(payload, Mapping):
            raise AllocationCandidateError("payload must be a mapping")
        return cls(
            ranked_opportunity_id=payload.get("ranked_opportunity_id"),
            ranking_run_id=payload.get("ranking_run_id"),
            scanner_run_id=payload.get("scanner_run_id"),
            source_opportunity_id=payload.get("source_opportunity_id"),
            strategy_signal_id=payload.get("strategy_signal_id"),
            metadata=dict(payload.get("metadata") or {}),
        )


@dataclass(frozen=True)
class AllocationPortfolioContext:
    portfolio_state_snapshot_id: str
    exposure_aggregate_id: str
    chain_strategy_budget_policy_id: Optional[str] = None
    metadata: Dict[str, Any] = field(default_factory=dict)
    allocation_portfolio_context_id: str = field(init=False)

    def __post_init__(self) -> None:
        portfolio_state_snapshot_id = _require_non_empty_string(
            "portfolio_state_snapshot_id",
            self.portfolio_state_snapshot_id,
        )
        exposure_aggregate_id = _require_non_empty_string(
            "exposure_aggregate_id",
            self.exposure_aggregate_id,
        )
        chain_strategy_budget_policy_id = (
            _require_non_empty_string(
                "chain_strategy_budget_policy_id",
                self.chain_strategy_budget_policy_id,
            )
            if self.chain_strategy_budget_policy_id is not None
            else None
        )
        metadata = _normalize_metadata(self.metadata)

        object.__setattr__(self, "portfolio_state_snapshot_id", portfolio_state_snapshot_id)
        object.__setattr__(self, "exposure_aggregate_id", exposure_aggregate_id)
        object.__setattr__(self, "chain_strategy_budget_policy_id", chain_strategy_budget_policy_id)
        object.__setattr__(self, "metadata", metadata)
        object.__setattr__(
            self,
            "allocation_portfolio_context_id",
            _stable_id(
                "allocation_portfolio_context",
                {
                    "portfolio_state_snapshot_id": portfolio_state_snapshot_id,
                    "exposure_aggregate_id": exposure_aggregate_id,
                    "chain_strategy_budget_policy_id": chain_strategy_budget_policy_id,
                },
            ),
        )

    def to_dict(self) -> Dict[str, Any]:
        payload = asdict(self)
        payload["metadata"] = dict(self.metadata)
        return payload

    @classmethod
    def from_dict(cls, payload: Mapping[str, Any]) -> "AllocationPortfolioContext":
        if not isinstance(payload, Mapping):
            raise AllocationCandidateError("payload must be a mapping")
        return cls(
            portfolio_state_snapshot_id=payload.get("portfolio_state_snapshot_id"),
            exposure_aggregate_id=payload.get("exposure_aggregate_id"),
            chain_strategy_budget_policy_id=payload.get("chain_strategy_budget_policy_id"),
            metadata=dict(payload.get("metadata") or {}),
        )


@dataclass(frozen=True)
class AllocationCandidate:
    chain: str
    strategy_id: str
    symbol: str
    pair: str
    side: str
    proposed_exposure_usd: float
    rank_score: float
    proposed_position_delta: int = 1
    venue: Optional[str] = None
    conflict_keys: List[str] = field(default_factory=list)
    lineage: AllocationCandidateLineage = field(default_factory=lambda: AllocationCandidateLineage(
        ranked_opportunity_id="__invalid__",
        ranking_run_id="__invalid__",
        scanner_run_id="__invalid__",
    ))
    portfolio_context: AllocationPortfolioContext = field(default_factory=lambda: AllocationPortfolioContext(
        portfolio_state_snapshot_id="__invalid__",
        exposure_aggregate_id="__invalid__",
    ))
    metadata: Dict[str, Any] = field(default_factory=dict)
    allocation_candidate_id: str = field(init=False)

    def __post_init__(self) -> None:
        normalized_chain = _normalize_chain(self.chain)
        normalized_strategy_id = _normalize_strategy_id(self.strategy_id)
        normalized_symbol = _normalize_symbol(self.symbol)
        normalized_pair = _normalize_pair(self.pair)
        normalized_side = _normalize_side(self.side)
        normalized_proposed_exposure_usd = _normalize_positive_float(
            "proposed_exposure_usd",
            self.proposed_exposure_usd,
        )
        normalized_rank_score = _normalize_non_negative_float("rank_score", self.rank_score)
        normalized_proposed_position_delta = _normalize_positive_int(
            "proposed_position_delta",
            self.proposed_position_delta,
        )
        normalized_venue = (
            _require_non_empty_string("venue", self.venue).lower()
            if self.venue is not None
            else None
        )
        normalized_lineage = (
            self.lineage
            if isinstance(self.lineage, AllocationCandidateLineage)
            else AllocationCandidateLineage.from_dict(_mapping_from_value("lineage", self.lineage))
        )
        normalized_portfolio_context = (
            self.portfolio_context
            if isinstance(self.portfolio_context, AllocationPortfolioContext)
            else AllocationPortfolioContext.from_dict(
                _mapping_from_value("portfolio_context", self.portfolio_context)
            )
        )
        normalized_metadata = _normalize_metadata(self.metadata)

        normalized_conflict_keys = _normalize_string_list("conflict_keys", self.conflict_keys)
        if not normalized_conflict_keys:
            normalized_conflict_keys = build_default_conflict_keys(
                chain=normalized_chain,
                strategy_id=normalized_strategy_id,
                symbol=normalized_symbol,
                pair=normalized_pair,
                side=normalized_side,
            )

        object.__setattr__(self, "chain", normalized_chain)
        object.__setattr__(self, "strategy_id", normalized_strategy_id)
        object.__setattr__(self, "symbol", normalized_symbol)
        object.__setattr__(self, "pair", normalized_pair)
        object.__setattr__(self, "side", normalized_side)
        object.__setattr__(self, "proposed_exposure_usd", normalized_proposed_exposure_usd)
        object.__setattr__(self, "rank_score", normalized_rank_score)
        object.__setattr__(self, "proposed_position_delta", normalized_proposed_position_delta)
        object.__setattr__(self, "venue", normalized_venue)
        object.__setattr__(self, "conflict_keys", normalized_conflict_keys)
        object.__setattr__(self, "lineage", normalized_lineage)
        object.__setattr__(self, "portfolio_context", normalized_portfolio_context)
        object.__setattr__(self, "metadata", normalized_metadata)
        object.__setattr__(
            self,
            "allocation_candidate_id",
            _stable_id(
                "allocation_candidate",
                {
                    "chain": normalized_chain,
                    "strategy_id": normalized_strategy_id,
                    "symbol": normalized_symbol,
                    "pair": normalized_pair,
                    "side": normalized_side,
                    "proposed_exposure_usd": normalized_proposed_exposure_usd,
                    "rank_score": normalized_rank_score,
                    "proposed_position_delta": normalized_proposed_position_delta,
                    "venue": normalized_venue,
                    "lineage_id": normalized_lineage.allocation_candidate_lineage_id,
                    "portfolio_context_id": normalized_portfolio_context.allocation_portfolio_context_id,
                },
            ),
        )

    def to_dict(self) -> Dict[str, Any]:
        return {
            "chain": self.chain,
            "strategy_id": self.strategy_id,
            "symbol": self.symbol,
            "pair": self.pair,
            "side": self.side,
            "proposed_exposure_usd": self.proposed_exposure_usd,
            "rank_score": self.rank_score,
            "proposed_position_delta": self.proposed_position_delta,
            "venue": self.venue,
            "conflict_keys": list(self.conflict_keys),
            "lineage": self.lineage.to_dict(),
            "portfolio_context": self.portfolio_context.to_dict(),
            "metadata": dict(self.metadata),
            "allocation_candidate_id": self.allocation_candidate_id,
        }

    @classmethod
    def from_dict(cls, payload: Mapping[str, Any]) -> "AllocationCandidate":
        if not isinstance(payload, Mapping):
            raise AllocationCandidateError("payload must be a mapping")
        return cls(
            chain=payload.get("chain"),
            strategy_id=payload.get("strategy_id"),
            symbol=payload.get("symbol"),
            pair=payload.get("pair"),
            side=payload.get("side"),
            proposed_exposure_usd=payload.get("proposed_exposure_usd"),
            rank_score=payload.get("rank_score"),
            proposed_position_delta=payload.get("proposed_position_delta", 1),
            venue=payload.get("venue"),
            conflict_keys=list(payload.get("conflict_keys") or []),
            lineage=payload.get("lineage"),
            portfolio_context=payload.get("portfolio_context"),
            metadata=dict(payload.get("metadata") or {}),
        )


def build_default_conflict_keys(
    *,
    chain: str,
    strategy_id: str,
    symbol: str,
    pair: str,
    side: str,
) -> List[str]:
    return [
        f"chain:{chain}",
        f"strategy:{strategy_id}",
        f"symbol:{symbol}",
        f"pair:{pair}",
        f"side:{side}",
        f"pair_side:{pair}:{side}",
        f"chain_strategy:{chain}:{strategy_id}",
    ]


def normalize_allocation_candidate(candidate: Any) -> AllocationCandidate:
    if isinstance(candidate, AllocationCandidate):
        return candidate
    payload = _mapping_from_value("candidate", candidate)
    return AllocationCandidate.from_dict(payload)


def allocation_candidates_conflict(
    first_candidate: Any,
    second_candidate: Any,
) -> bool:
    first = normalize_allocation_candidate(first_candidate)
    second = normalize_allocation_candidate(second_candidate)
    return bool(set(first.conflict_keys).intersection(second.conflict_keys))


def allocation_candidate_conflict_reasons(
    first_candidate: Any,
    second_candidate: Any,
) -> List[str]:
    first = normalize_allocation_candidate(first_candidate)
    second = normalize_allocation_candidate(second_candidate)
    return sorted(set(first.conflict_keys).intersection(second.conflict_keys))


def allocation_candidate_from_ranked_opportunity(
    *,
    ranked_opportunity: Any,
    portfolio_context: Any,
    proposed_exposure_usd: Any,
    side: Any,
    rank_score: Any | None = None,
    proposed_position_delta: int = 1,
    venue: Any | None = None,
    metadata: Optional[Mapping[str, Any]] = None,
) -> AllocationCandidate:
    opportunity = _mapping_from_value("ranked_opportunity", ranked_opportunity)
    normalized_portfolio_context = (
        portfolio_context
        if isinstance(portfolio_context, AllocationPortfolioContext)
        else AllocationPortfolioContext.from_dict(_mapping_from_value("portfolio_context", portfolio_context))
    )

    lineage = AllocationCandidateLineage(
        ranked_opportunity_id=opportunity.get("ranked_opportunity_id"),
        ranking_run_id=opportunity.get("ranking_run_id"),
        scanner_run_id=opportunity.get("scanner_run_id"),
        source_opportunity_id=opportunity.get("source_opportunity_id"),
        strategy_signal_id=opportunity.get("strategy_signal_id"),
        metadata=dict(opportunity.get("lineage_metadata") or {}),
    )

    resolved_rank_score = rank_score
    if resolved_rank_score is None:
        if "rank_score" not in opportunity:
            raise AllocationCandidateError(
                "ranked_opportunity must include rank_score when rank_score is not provided separately"
            )
        resolved_rank_score = opportunity.get("rank_score")

    symbol_value = opportunity.get("symbol")
    pair_value = opportunity.get("pair")
    if pair_value is None:
        pair_value = symbol_value

    merged_metadata: Dict[str, Any] = dict(opportunity.get("metadata") or {})
    if metadata:
        merged_metadata.update(dict(metadata))

    return AllocationCandidate(
        chain=opportunity.get("chain"),
        strategy_id=opportunity.get("strategy_id"),
        symbol=symbol_value,
        pair=pair_value,
        side=side,
        proposed_exposure_usd=proposed_exposure_usd,
        rank_score=resolved_rank_score,
        proposed_position_delta=proposed_position_delta,
        venue=venue if venue is not None else opportunity.get("venue"),
        lineage=lineage,
        portfolio_context=normalized_portfolio_context,
        metadata=merged_metadata,
    )
